package escalation

import (
	"strings"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

func TestExecutionHintParse_ValidTierLabels(t *testing.T) {
	cases := []struct {
		label string
		want  ModelTier
	}{
		{"tier:cheap", TierCheap},
		{"tier:standard", TierStandard},
		{"tier:smart", TierSmart},
	}

	for _, tc := range cases {
		t.Run(tc.label, func(t *testing.T) {
			b := &bead.Bead{Labels: []string{tc.label}}
			hint := ParseExecutionHint(b)
			if hint.RequestedTier != tc.want {
				t.Fatalf("requested tier: want %q, got %q", tc.want, hint.RequestedTier)
			}
			if hint.Source != ExecutionIntentSourceBeadHint {
				t.Fatalf("source: want bead_hint, got %q", hint.Source)
			}
		})
	}
}

func TestExecutionHintParse_SmartRequiresJustification(t *testing.T) {
	t.Run("missing", func(t *testing.T) {
		b := &bead.Bead{Labels: []string{"tier:smart"}}
		hint := ParseExecutionHint(b)
		if hint.RequestedTier != TierSmart {
			t.Fatalf("requested tier: want smart, got %q", hint.RequestedTier)
		}
		if hint.SmartJustification != "" {
			t.Fatalf("smart justification must be empty when absent, got %q", hint.SmartJustification)
		}
		findings := LintExecutionHints(b)
		if len(findings) != 1 {
			t.Fatalf("expected 1 finding, got %d", len(findings))
		}
		if findings[0].Message != "bead uses tier:smart but has no SMART JUSTIFICATION section" {
			t.Fatalf("unexpected finding: %+v", findings[0])
		}
	})

	t.Run("present", func(t *testing.T) {
		b := &bead.Bead{
			Labels:      []string{"tier:smart"},
			Description: "PROBLEM\nhard decision\n\nSMART JUSTIFICATION:\nThis bead decides the durable execution-hint contract.\n",
		}
		hint := ParseExecutionHint(b)
		if hint.SmartJustification == "" {
			t.Fatal("smart justification must be extracted when present")
		}
		if !strings.Contains(hint.SmartJustification, "durable execution-hint contract") {
			t.Fatalf("unexpected smart justification: %q", hint.SmartJustification)
		}
		if findings := LintExecutionHints(b); len(findings) != 0 {
			t.Fatalf("expected no lint findings, got %+v", findings)
		}
	})
}

func TestExecutionHintLint_RejectsDurableRoutePins(t *testing.T) {
	b := &bead.Bead{
		Labels: []string{"harness:claude", "provider:openai"},
		Extra: map[string]any{
			"execution-model": "gpt-5.5",
		},
	}

	findings := LintExecutionHints(b)
	if len(findings) != 3 {
		t.Fatalf("expected 3 findings, got %d: %+v", len(findings), findings)
	}

	want := map[string]bool{
		"harness":         false,
		"provider":        false,
		"execution-model": false,
	}
	for _, finding := range findings {
		switch finding.Field {
		case "harness", "provider", "execution-model":
			want[finding.Field] = true
		default:
			t.Fatalf("unexpected finding field: %q", finding.Field)
		}
		if finding.Message == "" {
			t.Fatalf("finding must carry a message: %+v", finding)
		}
	}
	for field, seen := range want {
		if !seen {
			t.Fatalf("missing finding for %s", field)
		}
	}
}

func TestInferTier_NilBead(t *testing.T) {
	if got := InferTier(nil); got != TierCheap {
		t.Fatalf("nil bead: want %q, got %q", TierCheap, got)
	}
}

func TestInferTier_ExplicitTierLabel(t *testing.T) {
	cases := []struct {
		label string
		want  ModelTier
	}{
		{"tier:smart", TierSmart},
		{"tier:standard", TierStandard},
		{"tier:cheap", TierCheap},
		{"TIER:SMART", TierSmart},
	}
	for _, c := range cases {
		b := &bead.Bead{Labels: []string{c.label}}
		if got := InferTier(b); got != c.want {
			t.Errorf("label %q: want %q, got %q", c.label, c.want, got)
		}
	}
}

func TestInferTier_ExplicitTierLabelOverridesPriority(t *testing.T) {
	// An explicit tier wins over priority:critical, which would otherwise
	// route to smart.
	b := &bead.Bead{Labels: []string{"priority:critical", "tier:cheap"}}
	if got := InferTier(b); got != TierCheap {
		t.Fatalf("explicit tier should win: got %q", got)
	}
}

func TestInferTier_PriorityCritical(t *testing.T) {
	b := &bead.Bead{Labels: []string{"priority:critical", "kind:chore"}}
	if got := InferTier(b); got != TierSmart {
		t.Fatalf("critical priority: want smart, got %q", got)
	}
}

func TestInferTier_PriorityHighBug(t *testing.T) {
	b := &bead.Bead{Labels: []string{"priority:high", "kind:bug"}}
	if got := InferTier(b); got != TierSmart {
		t.Fatalf("high-priority bug: want smart, got %q", got)
	}
}

func TestInferTier_PriorityHighEnhancement(t *testing.T) {
	b := &bead.Bead{Labels: []string{"priority:high", "kind:enhancement"}}
	if got := InferTier(b); got != TierStandard {
		t.Fatalf("high-priority enhancement: want standard, got %q", got)
	}
}

func TestInferTier_PriorityLow(t *testing.T) {
	b := &bead.Bead{Labels: []string{"priority:low", "kind:bug"}}
	if got := InferTier(b); got != TierCheap {
		t.Fatalf("low priority: want cheap, got %q", got)
	}
}

func TestInferTier_KindBug(t *testing.T) {
	b := &bead.Bead{Labels: []string{"kind:bug"}}
	if got := InferTier(b); got != TierStandard {
		t.Fatalf("bug kind: want standard, got %q", got)
	}
}

func TestInferTier_KindChore(t *testing.T) {
	b := &bead.Bead{Labels: []string{"kind:chore"}}
	if got := InferTier(b); got != TierCheap {
		t.Fatalf("chore kind: want cheap, got %q", got)
	}
}

func TestInferTier_KindEnhancement(t *testing.T) {
	b := &bead.Bead{Labels: []string{"kind:enhancement"}}
	if got := InferTier(b); got != TierStandard {
		t.Fatalf("enhancement kind: want standard, got %q", got)
	}
}

func TestInferTier_IssueTypeFallback(t *testing.T) {
	b := &bead.Bead{IssueType: "bug"}
	if got := InferTier(b); got != TierStandard {
		t.Fatalf("issue_type bug: want standard, got %q", got)
	}
}

func TestInferTier_ScopeShort(t *testing.T) {
	b := &bead.Bead{Description: "fix typo"}
	if got := InferTier(b); got != TierCheap {
		t.Fatalf("short scope: want cheap, got %q", got)
	}
}

func TestInferTier_ScopeMedium(t *testing.T) {
	b := &bead.Bead{Description: strings.Repeat("x", 2000)}
	if got := InferTier(b); got != TierStandard {
		t.Fatalf("medium scope: want standard, got %q", got)
	}
}

func TestInferTier_ScopeLarge(t *testing.T) {
	b := &bead.Bead{Description: strings.Repeat("x", 5000)}
	if got := InferTier(b); got != TierSmart {
		t.Fatalf("large scope: want smart, got %q", got)
	}
}

func TestInferTier_NoMetadataDefaultsCheap(t *testing.T) {
	b := &bead.Bead{Title: "do thing"}
	if got := InferTier(b); got != TierCheap {
		t.Fatalf("no metadata: want cheap, got %q", got)
	}
}

func TestTierToProfile(t *testing.T) {
	cases := map[ModelTier]string{
		TierSmart:     "smart",
		TierStandard:  "standard",
		TierCheap:     "cheap",
		ModelTier(""): "cheap",
	}
	for tier, want := range cases {
		if got := TierToProfile(tier); got != want {
			t.Errorf("TierToProfile(%q): want %q, got %q", tier, want, got)
		}
	}
}

package cmd

import (
	"context"
	"errors"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/agent/workerprobe"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
	serverpkg "github.com/DocumentDrivenDX/ddx/internal/server"
	"github.com/spf13/cobra"
)

// Exit codes for ddx try terminal outcomes. These are specific to ddx try
// and intentionally do not reuse the generic ExitCode* constants because
// the bead-execution outcome vocabulary is distinct from generic CLI errors.
const (
	tryExitSuccess         = 0 // success or already_satisfied
	tryExitPreservedOrNone = 1 // preserved_for_review or no_changes
	tryExitFailed          = 2 // execution_failed or any other terminal non-success
)

// newTryCommand creates the top-level "ddx try <bead-id>" command.
// It targets a single specific bead through the full production execution
// machinery (claim → execute → land → review), unlike "ddx work" which drains
// the queue by picker priority and cannot force a specific bead.
func (f *CommandFactory) newTryCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:          "try <bead-id>",
		Short:        "Execute a specific bead through the production machinery",
		SilenceUsage: true,
		Long: `try executes a single named bead through the full production
execution machinery: claim → execute → land → review.

Unlike "ddx work" which drains the queue by picker priority, "ddx try"
targets a specific bead ID. This is useful for:
  - Operator-driven debugging when a bead misbehaves under autonomous drain
  - Deterministic queue ordering during refactor execution (dispatch each child
    in dep order with an explicit ID)
  - Path-comparison studies that need to execute one fixture bead at a time

Pre-flight checks (run before any claim is issued):
  - bead not found → non-zero exit with "bead not found: <id>"
  - bead not claimable (status=closed, cancelled, etc.) → non-zero exit
  - bead has unmet dependencies → non-zero exit listing the blockers

Review is on by default. --no-review is a break-glass override and
requires --no-review-i-know-what-im-doing. A bead label of review:skip
is only honored when it also carries a sibling review:skip-reason:*
label; otherwise the label is ignored.

Flag plumbing is identical to "ddx work": --harness, --model, --provider,
--profile, --effort are forwarded to the agent as opaque passthrough
constraints. DDx does not validate or branch on their string values.

Exit codes:
  0  success or already_satisfied
  1  preserved_for_review or no_changes
  2  execution_failed or any other terminal non-success
`,
		Example: `  # Execute a specific bead
  ddx try ddx-abc12345

  # Execute with an explicit harness and model
  ddx try ddx-abc12345 --harness codex --model gpt-5.4-mini

  # Execute without the post-merge review step (break-glass only)
  ddx try ddx-abc12345 --no-review --no-review-i-know-what-im-doing`,
		Args: cobra.ExactArgs(1),
		RunE: f.runTry,
	}

	// Routing knobs — identical to "ddx work" passthrough surface.
	cmd.Flags().String("project", "", "Target project root path or name (default: CWD git root). Env: DDX_PROJECT_ROOT")
	cmd.Flags().String("from", "", "Base git revision to start from (default: HEAD)")
	cmd.Flags().String("harness", "", "Agent harness constraint (passthrough; ddx try does not validate)")
	cmd.Flags().String("model", "", "Model constraint (passthrough; ddx try does not validate)")
	cmd.Flags().String("profile", agent.DefaultRoutingProfile, "Routing profile: default, cheap, fast, or smart")
	cmd.Flags().String("provider", "", "Provider constraint (passthrough; ddx try does not validate)")
	cmd.Flags().String("model-ref", "", "Model catalog reference (e.g. code-medium); resolved via the model catalog")
	cmd.Flags().String("effort", "", "Effort level")
	cmd.Flags().Bool("no-review", false, "Skip post-merge review (break-glass: requires --no-review-i-know-what-im-doing)")
	cmd.Flags().Bool("no-review-i-know-what-im-doing", false, "Break-glass acknowledgement required when using --no-review")
	cmd.Flags().String("review-harness", "", "Harness for the post-merge reviewer (default: same as implementation harness)")
	cmd.Flags().String("review-model", "", "Model override for the post-merge reviewer (default: smart tier)")
	cmd.Flags().Duration("request-timeout", 0, "Per-request provider wall-clock timeout; overrides project config and model-class defaults")
	cmd.Flags().Int("min-power", 0, "Minimum model power required (0 = unconstrained)")
	cmd.Flags().Int("max-power", 0, "Maximum model power allowed (0 = unconstrained)")

	return cmd
}

// runTry is the RunE for "ddx try <bead-id>".
func (f *CommandFactory) runTry(cmd *cobra.Command, args []string) error {
	beadID := args[0]

	projectFlag, _ := cmd.Flags().GetString("project")
	projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
	fromRev, _ := cmd.Flags().GetString("from")
	harness, _ := cmd.Flags().GetString("harness")
	model, _ := cmd.Flags().GetString("model")
	profile, _ := cmd.Flags().GetString("profile")
	provider, _ := cmd.Flags().GetString("provider")
	modelRef, _ := cmd.Flags().GetString("model-ref")
